  // range sum をするときは，M1は(0, 0)だが初期化は(0, 1)であることに注意！



  LazySegmentTree(int n, const F f, const G g, const H h,

                  const Monoid &M1, const OperatorMonoid OM0)

      : f(f), g(g), h(h), M1(M1), OM0(OM0) {

    sz = 1;

