template <typename MonoidType, typename OperatorType>

struct LazySegNode {

    MonoidType value;

    OperatorType lazy_value;

    bool need_update;

    LazySegNode *ch[2];



    LazySegNode() {}

    LazySegNode(MonoidType value_, OperatorType lazy_value_) :

        value(value_), lazy_value(lazy_value_) {

        need_update = false;

        ch[0] = ch[1] = nullptr;

    }

};



template <typename MonoidType, typename OperatorType, class SegFunc, typename IdxType = int>

struct DynamicLazySegmentTree {

    // node, identity element

    using LNode = LazySegNode<MonoidType, OperatorType>;

    IdxType n;

    LNode *root;

    MonoidType E0;

    OperatorType E1;



    DynamicLazySegmentTree() {}

    DynamicLazySegmentTree(IdxType n_, MonoidType E0_, OperatorType E1_) :

        E0(E0_), E1(E1_) {

        root = new LNode(E0_, E1_);

        n = 1; while(n < n_) n *= 2;

    }



    void eval(LNode *node, IdxType l, IdxType r) {

        if(!node->need_update) return;

        node->value = SegFunc::update(node->value, SegFunc::accumulate(node->lazy_value, r - l));

        if(r - l > 1) {

            if(!node->ch[0]) node->ch[0] = new LNode(E0, E1);

            if(!node->ch[1]) node->ch[1] = new LNode(E0, E1);

            node->ch[0]->lazy_value = SegFunc::lazy_update(node->ch[0]->lazy_value, node->lazy_value);

            node->ch[1]->lazy_value = SegFunc::lazy_update(node->ch[1]->lazy_value, node->lazy_value);

            node->ch[0]->need_update = node->ch[1]->need_update = true;

        }

        node->lazy_value = E1;

        node->need_update = false;

    }



    void update(LNode *node, IdxType a, IdxType b, OperatorType x,

                IdxType l, IdxType r) {

        eval(node, l, r);

        if(b <= l or r <= a) return;

        if(a <= l and r <= b) {

            node->lazy_value = SegFunc::lazy_update(node->lazy_value, x);

            node->need_update = true;

            eval(node, l, r);

        }

        else {

            IdxType mid = (l + r) / 2;



            MonoidType vl = E0, vr = E0;

            if(!(b <= l or mid <= a)) {

                if(!node->ch[0]) node->ch[0] = new LNode(E0, E1);

                update(node->ch[0], a, b, x, l, mid);

                vl = node->ch[0]->value;

            }

            if(!(b <= mid or r <= a)) {

                if(!node->ch[1]) node->ch[1] = new LNode(E0, E1);

                update(node->ch[1], a, b, x, mid, r);

                vr = node->ch[1]->value;

            }

            node->value = SegFunc::combine(vl, vr);

